import { unstable_cacheTag as cacheTag } from 'next/cache';

let productCatalog = [
  {
    id: 1,
    sku: 'LAP-001',
    name: 'Laptop Pro 15"',
    price: 999,
    inventory: 14,
    availability: 'In stock'
  },
  {
    id: 2,
    sku: 'PHN-002',
    name: 'Phone Max',
    price: 699,
    inventory: 32,
    availability: 'In stock'
  },
  {
    id: 3,
    sku: 'TAB-003',
    name: 'Tablet Air',
    price: 499,
    inventory: 0,
    availability: 'Backorder'
  },
  {
    id: 4,
    sku: 'HDP-004',
    name: 'Noise Canceling Headphones',
    price: 199,
    inventory: 51,
    availability: 'In stock'
  },
  {
    id: 5,
    sku: 'WAT-005',
    name: 'Smart Watch',
    price: 299,
    inventory: 8,
    availability: 'Low stock'
  }
];

function wait(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export async function getAllProducts() {
  'use cache';
  cacheTag('products');

  await wait(100);

  return productCatalog;
}

export async function syncProductCatalog() {
  await wait(1200);

  productCatalog = productCatalog.map((product, index) => {
    const inventoryShift = (index % 3) - 1;
    const nextInventory = Math.max(product.inventory + inventoryShift * 3 + 2, 0);

    return {
      ...product,
      price: product.price + (index + 1) * 5,
      inventory: nextInventory,
      availability:
        nextInventory === 0
          ? 'Out of stock'
          : nextInventory < 10
            ? 'Low stock'
            : 'In stock'
    };
  });
}

import { revalidateTag, unstable_after as after } from 'next/cache';
import { getAllProducts, syncProductCatalog } from '@/lib/db';

async function syncLatestCatalog() {
  'use server';

  after(async () => {
    await syncProductCatalog();
    revalidateTag('products', 'max');
  });
}

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ padding: '32px', fontFamily: 'Arial, sans-serif' }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: '24px',
          marginBottom: '24px'
        }}
      >
        <div>
          <p
            style={{
              margin: '0 0 8px',
              textTransform: 'uppercase',
              letterSpacing: '0.08em',
              color: '#6b7280',
              fontSize: '12px'
            }}
          >
            Admin
          </p>
          <h1 style={{ margin: 0, fontSize: '32px' }}>Product catalog</h1>
          <p style={{ margin: '12px 0 0', color: '#4b5563', maxWidth: '720px' }}>
            Browse the current catalog snapshot quickly. When upstream ERP/PIM data changes,
            trigger a background sync and keep working while shared catalog views update shortly
            after.
          </p>
        </div>

        <form action={syncLatestCatalog}>
          <button
            type="submit"
            style={{
              border: 0,
              borderRadius: '10px',
              background: '#111827',
              color: '#fff',
              padding: '12px 18px',
              fontSize: '14px',
              fontWeight: 600,
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <div
        style={{
          padding: '16px',
          border: '1px solid #e5e7eb',
          borderRadius: '12px',
          marginBottom: '20px',
          background: '#f9fafb',
          color: '#374151'
        }}
      >
        Sync runs in the background. This page stays responsive immediately after submit, and any
        view using the <code>products</code> cache tag will refresh shortly after revalidation.
      </div>

      <div style={{ overflowX: 'auto' }}>
        <table
          style={{
            width: '100%',
            borderCollapse: 'collapse',
            border: '1px solid #e5e7eb',
            borderRadius: '12px',
            overflow: 'hidden'
          }}
        >
          <thead style={{ background: '#f3f4f6', textAlign: 'left' }}>
            <tr>
              <th style={{ padding: '14px' }}>SKU</th>
              <th style={{ padding: '14px' }}>Product</th>
              <th style={{ padding: '14px' }}>Price</th>
              <th style={{ padding: '14px' }}>Inventory</th>
              <th style={{ padding: '14px' }}>Availability</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderTop: '1px solid #e5e7eb' }}>
                <td style={{ padding: '14px', fontFamily: 'monospace' }}>{product.sku}</td>
                <td style={{ padding: '14px' }}>{product.name}</td>
                <td style={{ padding: '14px' }}>${product.price}</td>
                <td style={{ padding: '14px' }}>{product.inventory}</td>
                <td style={{ padding: '14px' }}>{product.availability}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}

